learning/7-Array/Array.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title Array
 * @dev Fixed-size and dynamic arrays
 */
contract Array {
    uint256[3] public fixedArray;
    uint256[] public dynamicArray;

    function push(uint256 x) external {
        dynamicArray.push(x);
    }

    function getLength() external view returns (uint256) {
        return dynamicArray.length;
    }

    function setFixed(uint256 index, uint256 value) external {
        require(index < 3, "Out of bounds");
        fixedArray[index] = value;
    }
}

learning/8-Loops/Loops.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title Loops
 * @dev for, while — use carefully to avoid gas limits
 */
contract Loops {
    uint256[] public numbers;

    function addNumbers(uint256[] calldata _numbers) external {
        for (uint256 i = 0; i < _numbers.length; i++) {
            numbers.push(_numbers[i]);
        }
    }

    function sum() external view returns (uint256 total) {
        for (uint256 i = 0; i < numbers.length; i++) {
            total += numbers[i];
        }
    }
}

learning/9-Conditionals/Conditionals.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title Conditionals
 * @dev if/else, require, ternary
 */
contract Conditionals {
    function check(uint256 x) external pure returns (string memory) {
        if (x < 10) return "small";
        else if (x < 100) return "medium";
        else return "large";
    }

    function onlyPositive(uint256 x) external pure returns (uint256) {
        require(x > 0, "Must be positive");
        return x;
    }

    function min(uint256 a, uint256 b) external pure returns (uint256) {
        return a < b ? a : b;  // ternary
    }
}

